{"file_path": "/project/ktlint-ruleset-standard/src/main/kotlin/com/pinterest/ktlint/ruleset/standard/rules/DiscouragedCommentDirectiveRule.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.ElementType.BLOCK_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.ElementType.EOL_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode

/**
 * Detects the usage of deprecated ktlint-disable/ktlint-enable directives and reports them as violations.
 * These directives are no longer supported and should be replaced with @Suppress annotations.
 *
 * This rule cannot be suppressed as it helps in migration to the new suppression mechanism.
 */
public class DiscouragedCommentDirectiveRule :
    StandardRule("discouraged-comment-location"),
    Rule.Experimental {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        when (node.elementType) {
            EOL_COMMENT -> {
                val text = node.text.removePrefix("//").trim()
                if (text.startsWith("ktlint-disable")) {
                    emit(
                        node.startOffset,
                        "The ktlint-disable directive is no longer supported. Replace with @Suppress annotation.",
                        false,
                    )
                }
            }
            BLOCK_COMMENT -> {
                val text = node.text.removePrefix("/*").removeSuffix("*/").trim()
                if (text.startsWith("ktlint-disable")) {
                    emit(
                        node.startOffset,
                        "The ktlint-disable directive is no longer supported. Replace with @Suppress annotation.",
                        false,
                    )
                } else if (text.startsWith("ktlint-enable")) {
                    emit(
                        node.startOffset,
                        "The ktlint-enable directive is no longer supported. Remove this comment or replace with proper @Suppress annotation usage.",
                        false,
                    )
                }
            }
            else -> Unit
        }
    }
}

public val DISCOURAGED_COMMENT_DIRECTIVE_RULE_ID: RuleId = DiscouragedCommentDirectiveRule().ruleId
"}

